package rt.ws.security.org.apache.cxf.ws.security.policy.builders;

public class WSS11Builder implements AssertionBuilder < Element > { public WSS11Builder ( ) { } public Assertion build ( Element element , AssertionBuilderFactory factory ) throws IllegalArgumentException { SPConstants consts = SP11Constants . SP_NS . equals ( element . getNamespaceURI ( ) ) ? SP11Constants . INSTANCE : SP12Constants . INSTANCE ; Wss11 wss11 = new Wss11 ( consts ) ; processAlternative ( element , wss11 , consts ) ; return wss11 ; } public QName [ ] getKnownElements ( ) { return new QName [ ] { SP11Constants . WSS11 , SP12Constants . WSS11 } ; } private void processAlternative ( Element element , Wss11 parent , SPConstants consts ) { Element polEl = PolicyConstants . findPolicyElement ( element ) ; if ( polEl != null ) { Element child = DOMUtils . getFirstElement ( polEl ) ; while ( child != null ) { String name = child . getLocalName ( ) ; if ( SPConstants . MUST_SUPPORT_REF_KEY_IDENTIFIER . equals ( name ) ) { parent . setMustSupportRefKeyIdentifier ( true ) ; } else if ( SPConstants . MUST_SUPPORT_REF_ISSUER_SERIAL . equals ( name ) ) { parent . setMustSupportRefIssuerSerial ( true ) ; } else if ( SPConstants . MUST_SUPPORT_REF_EXTERNAL_URI . equals ( name ) ) { parent . setMustSupportRefExternalURI ( true ) ; } else if ( SPConstants . MUST_SUPPORT_REF_EMBEDDED_TOKEN . equals ( name ) ) { parent . setMustSupportRefEmbeddedToken ( true ) ; } else if ( SPConstants . MUST_SUPPORT_REF_THUMBPRINT . equals ( name ) ) { parent . setMustSupportRefThumbprint ( true ) ; } else if ( SPConstants . MUST_SUPPORT_REF_ENCRYPTED_KEY . equals ( name ) ) { parent . setMustSupportRefEncryptedKey ( true ) ; } else if ( SPConstants . REQUIRE_SIGNATURE_CONFIRMATION . equals ( name ) ) { parent . setRequireSignatureConfirmation ( true ) ; } child = DOMUtils . getNextElement ( child ) ; } } } }